// C++ Memoization for Fibonacci
int memo[100]; // Initialize with -1
int fib(int n) {
    if (n <= 1) return n;
    if (memo[n] != -1) return memo[n]; // Check 'sticky note'
    return memo[n] = fib(n-1) + fib(n-2); // Save result
}

// C++ Tabulation for Fibonacci
int fib(int n) {
    int f[n+1];
    f[0] = 0; f[1] = 1;
    for (int i = 2; i <= n; i++)
        f[i] = f[i-1] + f[i-2]; // Build the table
    return f[n];
}

